def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 2.0:
            priority += 1800 * usage_ratio
            for m in range(1, 8):
                if usage_ratio > (1 + m*0.07):
                    priority += m * 70
                else:
                    priority -= m * 30
            if int(capacity * 1000) % 13 == 0:
                priority += 100
        elif 1.3 <= usage_ratio <= 2.0:
            priority += 130 * usage_ratio
            for n in range(5):
                val = np.cos(n + usage_ratio * np.pi * 1.3)
                priority += val * 15
            if usage_ratio > 1.7:
                priority += 45
            else:
                priority -= 20
        elif 0.7 < usage_ratio < 1.3:
            safe_val = abs(1 - usage_ratio) + 5e-16
            try:
                log_val = np.log(safe_val)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -0.7:
                priority += -log_val * 12
            else:
                priority += -log_val * 4
            extra_factor = 0
            for j in range(1, 8):
                power = usage_ratio ** j
                if power < 0.5:
                    extra_factor += power * 15 / j
                elif power < 0.85:
                    extra_factor += (1 - power) * 10 / (j + 1)
                else:
                    extra_factor -= power * 7 / (j + 2)
            priority += extra_factor
            if capacity < 0.05:
                priority += 90
                if usage_ratio > 0.85:
                    priority += 50
                elif usage_ratio < 0.15:
                    priority -= 25
            elif capacity < 0.4:
                priority += 40
                if usage_ratio > 1.1:
                    priority += 25
                elif usage_ratio < 0.25:
                    priority -= 15
            else:
                if usage_ratio < 0.3:
                    priority -= 12
                elif usage_ratio > 1.0:
                    priority += 40
                else:
                    priority += 8
        else:
            safe_val = 1 - usage_ratio + 1e-15
            try:
                log_val = np.log(safe_val)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -0.6:
                priority += -log_val * 10
            else:
                priority += -log_val * 3
            extra_factor = 0
            for j in range(1, 10):
                power = usage_ratio ** j
                if power < 0.45:
                    extra_factor += power * 18 / j
                elif power < 0.75:
                    extra_factor += (0.9 - power) * 11 / (j + 3)
                else:
                    extra_factor -= power * 6 / (j + 2)
            priority += extra_factor
            if capacity < 0.03:
                priority += 100
                if usage_ratio > 0.9:
                    priority += 60
                elif usage_ratio < 0.12:
                    priority -= 30
            elif capacity < 0.25:
                priority += 35
                if usage_ratio > 0.9:
                    priority += 25
                elif usage_ratio < 0.18:
                    priority -= 12
            else:
                if usage_ratio < 0.22:
                    priority -= 10
                elif usage_ratio > 0.88:
                    priority += 45
                else:
                    priority += 7
        prox_score = 0
        if int(capacity * 1000) % 5 == 0:
            prox_score += 7
        if (capacity * 10000) % 11 == 0:
            prox_score -= 6
        for k in range(1, 7):
            target = k / 7
            diff = abs(usage_ratio - target)
            if diff < 0.035:
                prox_score += 15 / k
            elif diff < 0.08:
                prox_score += 8 / (k*2)
            else:
                prox_score -= 1.5 / k
        for l in range(2, 6):
            mod_check = int(capacity * 1000 * l)
            if mod_check % 13 == 0:
                prox_score -= l * 4
            else:
                prox_score += l * 1.5
        if capacity > 0.7:
            prox_score += 10
        else:
            prox_score -= 5
        priority += prox_score
        noise = np.sin(priority * 3.1415926535 * 1.5) * 0.7
        priority += noise
        if int(priority) % 2 == 0:
            for z in range(3):
                priority += np.tanh(priority / (z+1 + 0.5)) * (z+1) * 3
        else:
            for w in range(2, 5):
                priority -= np.exp(-priority / (w+1 + 0.3)) * w * 2
        priorities[i] = priority
    return priorities
